import{_ as a,o as t,c as i,a0 as r}from"./chunks/framework.CSGB4SNl.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"vue/vue-day03.md","filePath":"vue/vue-day03.md"}'),o={name:"vue/vue-day03.md"};function l(u,e,n,d,s,c){return t(),i("div",null,[...e[0]||(e[0]=[r('<h4 id="动态给vue的data添加一个新的属性时会发生什么-怎样解决" tabindex="-1">动态给vue的data添加一个新的属性时会发生什么？怎样解决？ <a class="header-anchor" href="#动态给vue的data添加一个新的属性时会发生什么-怎样解决" aria-label="Permalink to &quot;动态给vue的data添加一个新的属性时会发生什么？怎样解决？&quot;">​</a></h4><ol><li>直接添加属性没法做到响应式更改，因为vue底层做响应式数据的话是通过Object.defineProperty，访问和设置他的值都可以触发get和set，但是添加不行，因为响应式数据已经设置好了添加新属性时并没有通过Object.defineProperty设置为响应式的</li><li>通过Vue.set向响应式变量中添加一个新属性、Object.assign()-这个是创建一个新的对象然后将原有的和新的进行合并</li></ol><h4 id="vue中组件和插件有什么区别" tabindex="-1">Vue中组件和插件有什么区别？ <a class="header-anchor" href="#vue中组件和插件有什么区别" aria-label="Permalink to &quot;Vue中组件和插件有什么区别？&quot;">​</a></h4><ol><li>插件：通过app.use()安装，用来拓展vue的功能全局方法、属性、指令、组件如vue-router、pinia、element-ui</li></ol><h4 id="vue组件之间的通信方式都有哪些" tabindex="-1">Vue组件之间的通信方式都有哪些？ <a class="header-anchor" href="#vue组件之间的通信方式都有哪些" aria-label="Permalink to &quot;Vue组件之间的通信方式都有哪些？&quot;">​</a></h4><ol><li>分类：父子组件间、兄弟组件间、祖孙与后代组件、非关系间组件</li><li>父子：子组件通过props接收父组件传来的值、子组件通过$emit向父组件提交自定义事件并传值，还有父组件ref拿到子组件实例，兄弟组件：EventBus创建一个事件总线、其中一方$emit提交自定义事件、另一方$on捕获自定义事件、通过共同父辈$parent/$root通信，祖先子孙：$attrs/$listeners向子孙组件传值、provide祖先定义inject子孙接收，vuex/pinia做全局数据共享</li></ol><h4 id="双向数据绑定是什么" tabindex="-1">双向数据绑定是什么 <a class="header-anchor" href="#双向数据绑定是什么" aria-label="Permalink to &quot;双向数据绑定是什么&quot;">​</a></h4><ol><li>双向数据绑定就是更新model层时view层也会更新，view更新时model也会更新，通过中间的viewmodel(监听器-监听数据和解析器-对每个元素节点的指令进行扫描解析，根据指令模板替换数据构成)层进行双向更新</li><li>过程new Vue初始化，对data进行响应式处理，找到data中的数据绑定的元素并初始化视图，同时定义一个更新函数和Watcher监听数据变化更新就调用更新函数，data中的某个key可能在视图中会出现多次，所以会有每个key都有管家进行管理，数据发送变化管家会通知所有Watcher</li></ol>',8)])])}const p=a(o,[["render",l]]);export{h as __pageData,p as default};
